import React from 'react';
import { useCurrentFrame, interpolate } from 'remotion';
import { PlacementBox } from '../../../lib/canvas';
import { pulsingIndicatorSchema, type PulsingIndicatorProps } from './schema';

export { pulsingIndicatorSchema, type PulsingIndicatorProps };

/**
 * A live status dot with a calm expanding-ring pulse, plus an optional label.
 * The pulse is keyed off `frame % period`, so it loops seamlessly and renders
 * deterministically (§1) — no timers. One steady ring, not a strobe.
 *
 * @example
 * <PulsingIndicator label="LIVE" />
 */
export const PulsingIndicator: React.FC<PulsingIndicatorProps> = ({
  color, size, label, labelColor, fontFamily, fontSize, period, placement,
}) => {
  const frame = useCurrentFrame();
  const t = ((frame % period) + period) % period / period;
  const ringScale = interpolate(t, [0, 1], [1, 2.6]);
  const ringOpacity = interpolate(t, [0, 1], [0.5, 0]);

  return (
    <PlacementBox placement={placement}>
      <div style={{ display: 'inline-flex', alignItems: 'center', gap: size * 0.7 }}>
        <div style={{ position: 'relative', width: size, height: size }}>
          <div
            style={{
              position: 'absolute',
              inset: 0,
              borderRadius: 999,
              background: color,
              transform: `scale(${ringScale})`,
              opacity: ringOpacity,
            }}
          />
          <div style={{ position: 'absolute', inset: 0, borderRadius: 999, background: color }} />
        </div>
        {label && (
          <span style={{ color: labelColor, fontFamily, fontSize, letterSpacing: '0.16em', textTransform: 'uppercase' }}>
            {label}
          </span>
        )}
      </div>
    </PlacementBox>
  );
};

import { z } from 'zod';
import { placementSchema } from '../../../lib/canvas-schemas';

/** Zod schema for {@link PulsingIndicator} props. */
export const pulsingIndicatorSchema = z.object({
  /** Discriminator literal — matches this entry's registry slug. Auto-populated when omitted. */
  kind: z.literal('pulsing-indicator').default('pulsing-indicator'),
  /** Dot + ring color. The earned accent by default. */
  color: z.string().default('var(--onda-accent, #D96B82)'),
  /** Dot diameter in px. */
  size: z.number().default(20),
  /** Optional label to the right of the dot. Empty hides it. */
  label: z.string().default('LIVE'),
  /** Label color. */
  labelColor: z.string().default('var(--onda-dim, #8E8E98)'),
  /** Label font family. */
  fontFamily: z.string().default('var(--onda-font-body, "Space Grotesk", sans-serif)'),
  /** Label font size in px. */
  fontSize: z.number().default(28),
  /** Frames per pulse cycle. */
  period: z.number().int().min(1).default(45),
  /** Where on the canvas this sits. */
  placement: placementSchema.optional(),
});

/** Inferred props for {@link PulsingIndicator}. */
export type PulsingIndicatorProps = z.infer<typeof pulsingIndicatorSchema>;
